A `debounce` function in JavaScript is used to limit the rate at which a function is executed, ensuring that it only runs after a specified delay since the last time it was invoked.

```javascript
function debounce(func, delay) {
    let timeoutId;
    return function(...args) {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => {
            func(...args);
        }, delay);
    };
}

// Example usage:
function handleResize() {
    console.log('Window resized');
}

window.addEventListener('resize', debounce(handleResize, 200));
```

In this example, the `handleResize` function will only be called 200 milliseconds after the user stops resizing the window.
